label("$C$", C, N);
label("$D$", D, S);
label("$E$", E, SW);
label("$F$", F, SE);
label("$X$", X, SW);
label("$Y$", Y, SE);
label("$Z$", Z, SE);
label("12", (A+B)/2, dir(90));
label("16", (B+F)/2, dir(0));
[/asy]

